INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvryrz10002ugv7xhnsiolz', 'SOAL-00001', 'Sebelum era internet modern, layanan komunikasi seperti telepon, televisi, dan data seringkali menggunakan infrastruktur jaringan yang terpisah. Istilah yang tepat untuk menggambarkan jenis jaringan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Jaringan Konvergen", "isCorrect": false}, {"id": "B", "text": "Jaringan Terintegrasi", "isCorrect": false}, {"id": "C", "text": "Jaringan Dedicated", "isCorrect": true}, {"id": "D", "text": "Jaringan Nirkabel", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.148', '2026-03-18 08:24:05.148', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvryrzf0003ugv7y1fi7hp1', 'SOAL-00002', 'Perkembangan teknologi jaringan telah mengubah paradigma dari jaringan yang terpisah-pisah menjadi satu kesatuan. Manakah pernyataan berikut yang paling tepat menggambarkan karakteristik utama ''Jaringan Converged''?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Hanya mendukung komunikasi suara dan video secara bersamaan.", "isCorrect": false}, {"id": "B", "text": "Menggunakan infrastruktur terpisah untuk setiap jenis layanan (suara, data, video).", "isCorrect": false}, {"id": "C", "text": "Mengintegrasikan berbagai jenis komunikasi (suara, data, video) dalam satu infrastruktur jaringan.", "isCorrect": true}, {"id": "D", "text": "Membutuhkan protokol yang berbeda untuk setiap jenis data yang ditransmisikan.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.162', '2026-03-18 08:24:05.162', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvryrzs0004ugv7e2brzgnq', 'SOAL-00003', 'Protokol standar yang menjadi fondasi utama dalam Jaringan Converged dan memungkinkan berbagai perangkat serta layanan untuk saling berkomunikasi di era internet adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "FTP/HTTP", "isCorrect": false}, {"id": "B", "text": "SMTP/POP3", "isCorrect": false}, {"id": "C", "text": "TCP/IP", "isCorrect": true}, {"id": "D", "text": "UDP/ICMP", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.175', '2026-03-18 08:24:05.175', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys050005ugv753rjw3kd', 'SOAL-00004', 'Media komunikasi yang menggunakan cahaya untuk mentransmisikan data dengan kecepatan sangat tinggi dan menjadi tulang punggung infrastruktur jaringan modern adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kabel koaksial", "isCorrect": false}, {"id": "B", "text": "Kabel UTP", "isCorrect": false}, {"id": "C", "text": "Serat optik", "isCorrect": true}, {"id": "D", "text": "Gelombang radio", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.188', '2026-03-18 08:24:05.188', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys0i0006ugv7q81fgqrb', 'SOAL-00005', 'Peningkatan kecepatan transfer data secara signifikan merupakan salah satu ciri kemajuan teknologi nirkabel. Generasi teknologi nirkabel yang mampu mencapai kecepatan gigabit per detik dan mendukung berbagai aplikasi canggih seperti IoT skala besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "2G", "isCorrect": false}, {"id": "B", "text": "3G", "isCorrect": false}, {"id": "C", "text": "4G", "isCorrect": false}, {"id": "D", "text": "5G", "isCorrect": true}]', 'D', 5, '2026-03-18 08:24:05.201', '2026-03-18 08:24:05.201', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys0w0007ugv7ubosj77f', 'SOAL-00006', 'Seiring dengan pertumbuhan perangkat yang terhubung ke internet, jumlah alamat IP yang tersedia menjadi krusial. Sistem pengalamatan yang dikembangkan untuk mengatasi keterbatasan jumlah alamat IP pada versi sebelumnya dan memiliki ruang alamat yang jauh lebih besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "IPv4", "isCorrect": false}, {"id": "B", "text": "MAC Address", "isCorrect": false}, {"id": "C", "text": "IPv6", "isCorrect": true}, {"id": "D", "text": "DNS", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.215', '2026-03-18 08:24:05.215', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys180008ugv7p0mpeq3g', 'SOAL-00007', 'Salah satu keunggulan utama IPv6 dibandingkan IPv4 adalah jumlah alamat yang jauh lebih banyak. Berapa bit yang digunakan oleh IPv6 untuk representasi alamat?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "32 bit", "isCorrect": false}, {"id": "B", "text": "64 bit", "isCorrect": false}, {"id": "C", "text": "128 bit", "isCorrect": true}, {"id": "D", "text": "256 bit", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.227', '2026-03-18 08:24:05.227', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys1j0009ugv7w0y6u0r1', 'SOAL-00008', 'Layanan yang memungkinkan pengguna menyimpan data dan menjalankan aplikasi di server yang dikelola oleh pihak ketiga melalui internet, sehingga mengurangi kebutuhan akan perangkat keras server fisik di lokasi pengguna, dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peer-to-Peer Computing", "isCorrect": false}, {"id": "B", "text": "Edge Computing", "isCorrect": false}, {"id": "C", "text": "Cloud Computing", "isCorrect": true}, {"id": "D", "text": "Local Area Network", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.239', '2026-03-18 08:24:05.239', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys1w000augv78qnt1g9i', 'SOAL-00009', 'Sebuah perusahaan startup sedang berkembang pesat dan membutuhkan infrastruktur IT yang fleksibel, scalable, dan hemat biaya tanpa harus membeli dan memelihara banyak server fisik. Solusi teknologi modern yang paling tepat untuk kebutuhan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membangun data center sendiri", "isCorrect": false}, {"id": "B", "text": "Menggunakan Cloud Computing", "isCorrect": true}, {"id": "C", "text": "Memperbanyak hard disk lokal", "isCorrect": false}, {"id": "D", "text": "Meningkatkan kecepatan koneksi internet saja", "isCorrect": false}]', 'B', 5, '2026-03-18 08:24:05.251', '2026-03-18 08:24:05.251', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys28000bugv7zqk63gsc', 'SOAL-00010', 'Konsep di mana berbagai perangkat mekanis atau digital dapat saling berkomunikasi dan mentransfer data melalui jaringan tanpa interaksi manusia secara langsung disebut...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Human-to-Human Communication", "isCorrect": false}, {"id": "B", "text": "Machine-to-Machine (M2M) Communication", "isCorrect": true}, {"id": "C", "text": "Peer-to-Peer File Sharing", "isCorrect": false}, {"id": "D", "text": "Client-Server Architecture", "isCorrect": false}]', 'B', 5, '2026-03-18 08:24:05.263', '2026-03-18 08:24:05.263', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys2m000cugv7rgtlng4k', 'SOAL-00011', 'Sebuah smart home memiliki lampu pintar, termostat otomatis, dan kamera keamanan yang semuanya terhubung ke internet dan dapat dikendalikan dari smartphone pengguna. Ini adalah contoh implementasi dari...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Cloud Computing", "isCorrect": false}, {"id": "B", "text": "Data Center Redundan", "isCorrect": false}, {"id": "C", "text": "Internet of Things (IoT)", "isCorrect": true}, {"id": "D", "text": "Jaringan Dedicated", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.277', '2026-03-18 08:24:05.277', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys2y000dugv7rld8ibd1', 'SOAL-00012', 'Untuk memastikan ketersediaan data yang tinggi dan mencegah kegagalan sistem total, sebuah perusahaan membangun infrastruktur penyimpanan data yang memiliki sistem cadangan atau paralel. Konsep ini dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Data Center Terdistribusi", "isCorrect": false}, {"id": "B", "text": "Data Center Virtual", "isCorrect": false}, {"id": "C", "text": "Data Center Redundan", "isCorrect": true}, {"id": "D", "text": "Data Center Lokal", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.289', '2026-03-18 08:24:05.289', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys3a000eugv7fw3bzsai', 'SOAL-00013', 'Sebuah layanan streaming video global harus memastikan layanannya selalu tersedia 24/7 tanpa gangguan, bahkan jika terjadi bencana alam di salah satu lokasi server. Solusi infrastruktur yang paling krusial untuk mencapai tujuan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Menggunakan server dengan spesifikasi tertinggi", "isCorrect": false}, {"id": "B", "text": "Membangun Data Center Redundan di lokasi geografis yang berbeda", "isCorrect": true}, {"id": "C", "text": "Hanya mengandalkan satu data center yang sangat besar", "isCorrect": false}, {"id": "D", "text": "Meningkatkan bandwidth koneksi internet ke pengguna", "isCorrect": false}]', 'B', 5, '2026-03-18 08:24:05.301', '2026-03-18 08:24:05.301', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys3l000fugv7lonx6yig', 'SOAL-00014', 'Perusahaan X masih menggunakan jaringan terpisah untuk telepon, TV kabel, dan koneksi internet di kantor pusatnya. Mereka ingin beralih ke Jaringan Converged. Keuntungan utama yang akan mereka dapatkan dari transisi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peningkatan kompleksitas pengelolaan jaringan.", "isCorrect": false}, {"id": "B", "text": "Peningkatan biaya investasi awal yang signifikan.", "isCorrect": false}, {"id": "C", "text": "Efisiensi biaya dan manajemen yang lebih sederhana karena satu infrastruktur.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat mendukung satu jenis layanan pada satu waktu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.312', '2026-03-18 08:24:05.312', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys3x000gugv7ta8zg64v', 'SOAL-00015', 'Mengapa serat optik lebih unggul dibandingkan kabel tembaga (misalnya UTP) untuk transmisi data jarak jauh dan kecepatan tinggi dalam Jaringan Converged?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Lebih murah dan mudah dipasang.", "isCorrect": false}, {"id": "B", "text": "Mentransmisikan data dalam bentuk sinyal listrik.", "isCorrect": false}, {"id": "C", "text": "Kurang rentan terhadap interferensi elektromagnetik dan memiliki bandwidth lebih besar.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat digunakan untuk jaringan lokal.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.324', '2026-03-18 08:24:05.324', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys4a000hugv7pzhp9noj', 'SOAL-00016', 'Dalam konteks IPv6, penggunaan format heksadesimal (misalnya, 2001:0db8:85a3:0000:0000:8a2e:0370:7334) untuk alamat IP dibandingkan notasi desimal bertitik pada IPv4 (misalnya, 192.168.1.1) memiliki tujuan utama untuk...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mempermudah mengingat alamat IP oleh pengguna awam.", "isCorrect": false}, {"id": "B", "text": "Mengurangi ukuran file konfigurasi jaringan.", "isCorrect": false}, {"id": "C", "text": "Meringkas representasi alamat yang panjang agar lebih efisien.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan keamanan jaringan secara inheren.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.337', '2026-03-18 08:24:05.337', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys4m000iugv7h9zjn9vh', 'SOAL-00017', 'Sebuah kota berencana menerapkan ''Smart City'' dengan sensor parkir pintar, sistem pengelolaan sampah otomatis, dan pemantauan kualitas udara secara real-time. Infrastruktur jaringan nirkabel seperti 5G akan sangat penting untuk mendukung proyek ini karena...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Harganya yang murah untuk pemasangan awal.", "isCorrect": false}, {"id": "B", "text": "Latensi tinggi yang cocok untuk transmisi data masif.", "isCorrect": false}, {"id": "C", "text": "Kecepatan tinggi, latensi rendah, dan kapasitas koneksi perangkat masif.", "isCorrect": true}, {"id": "D", "text": "Kebutuhan daya yang rendah untuk perangkat sensor.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.35', '2026-03-18 08:24:05.35', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys4z000jugv7cgpklchn', 'SOAL-00018', 'Seorang teknisi jaringan sedang merancang ulang infrastruktur untuk sebuah e-commerce besar yang tidak boleh mengalami downtime sedikit pun. Dia menyarankan penggunaan teknologi Data Center Redundan. Apa prinsip dasar yang ingin dicapai dengan rekomendasi ini?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mengurangi konsumsi energi secara drastis.", "isCorrect": false}, {"id": "B", "text": "Memastikan semua data disimpan secara lokal di setiap perangkat.", "isCorrect": false}, {"id": "C", "text": "Mencegah satu titik kegagalan (Single Point of Failure) agar layanan tetap berjalan.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan kecepatan akses data untuk pengguna individu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:24:05.362', '2026-03-18 08:24:05.362', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys5b000kugv7d53gfqjw', 'SOAL-00019', 'Dalam Cloud Computing, salah satu manfaat bagi pengguna adalah ''pay-as-you-go'' atau membayar sesuai penggunaan. Implikasi utama dari model ini bagi sebuah bisnis kecil yang baru memulai adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membutuhkan investasi awal yang sangat besar untuk hardware.", "isCorrect": false}, {"id": "B", "text": "Memungkinkan skalabilitas sumber daya tanpa komitmen jangka panjang.", "isCorrect": true}, {"id": "C", "text": "Mengharuskan pemeliharaan server secara mandiri.", "isCorrect": false}, {"id": "D", "text": "Membatasi akses ke aplikasi dan data hanya di lokasi fisik kantor.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:24:05.374', '2026-03-18 08:24:05.374', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvrys5n000lugv73su5o74y', 'SOAL-00020', 'Perusahaan telekomunikasi sedang dalam proses migrasi dari infrastruktur Jaringan Dedicated ke Jaringan Converged menggunakan TCP/IP. Tantangan teknis utama yang mungkin mereka hadapi dalam proses migrasi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kurangnya perangkat keras yang mendukung TCP/IP.", "isCorrect": false}, {"id": "B", "text": "Kompatibilitas antara sistem lama (analog) dengan protokol baru (digital) dan investasi besar.", "isCorrect": true}, {"id": "C", "text": "Keterbatasan jumlah alamat IP yang tersedia di Jaringan Converged.", "isCorrect": false}, {"id": "D", "text": "Peningkatan kecepatan internet yang tidak terkendali.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:24:05.386', '2026-03-18 08:24:05.386', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jja002eugv7w6a9uise', 'SOAL-00041', 'Sebelum era internet modern, layanan komunikasi seperti telepon, televisi, dan data seringkali menggunakan infrastruktur jaringan yang terpisah. Istilah yang tepat untuk menggambarkan jenis jaringan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Jaringan Konvergen", "isCorrect": false}, {"id": "B", "text": "Jaringan Terintegrasi", "isCorrect": false}, {"id": "C", "text": "Jaringan Dedicated", "isCorrect": true}, {"id": "D", "text": "Jaringan Nirkabel", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.149', '2026-03-18 08:28:34.149', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jjn002fugv7tws0qqh5', 'SOAL-00042', 'Perkembangan teknologi jaringan telah mengubah paradigma dari jaringan yang terpisah-pisah menjadi satu kesatuan. Manakah pernyataan berikut yang paling tepat menggambarkan karakteristik utama ''Jaringan Converged''?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Hanya mendukung komunikasi suara dan video secara bersamaan.", "isCorrect": false}, {"id": "B", "text": "Menggunakan infrastruktur terpisah untuk setiap jenis layanan (suara, data, video).", "isCorrect": false}, {"id": "C", "text": "Mengintegrasikan berbagai jenis komunikasi (suara, data, video) dalam satu infrastruktur jaringan.", "isCorrect": true}, {"id": "D", "text": "Membutuhkan protokol yang berbeda untuk setiap jenis data yang ditransmisikan.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.163', '2026-03-18 08:28:34.163', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jjv002gugv7c1h4ojxj', 'SOAL-00043', 'Protokol standar yang menjadi fondasi utama dalam Jaringan Converged dan memungkinkan berbagai perangkat serta layanan untuk saling berkomunikasi di era internet adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "FTP/HTTP", "isCorrect": false}, {"id": "B", "text": "SMTP/POP3", "isCorrect": false}, {"id": "C", "text": "TCP/IP", "isCorrect": true}, {"id": "D", "text": "UDP/ICMP", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.171', '2026-03-18 08:28:34.171', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jk4002hugv7enq3r1yd', 'SOAL-00044', 'Media komunikasi yang menggunakan cahaya untuk mentransmisikan data dengan kecepatan sangat tinggi dan menjadi tulang punggung infrastruktur jaringan modern adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kabel koaksial", "isCorrect": false}, {"id": "B", "text": "Kabel UTP", "isCorrect": false}, {"id": "C", "text": "Serat optik", "isCorrect": true}, {"id": "D", "text": "Gelombang radio", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.179', '2026-03-18 08:28:34.179', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jkc002iugv76w5md21h', 'SOAL-00045', 'Peningkatan kecepatan transfer data secara signifikan merupakan salah satu ciri kemajuan teknologi nirkabel. Generasi teknologi nirkabel yang mampu mencapai kecepatan gigabit per detik dan mendukung berbagai aplikasi canggih seperti IoT skala besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "2G", "isCorrect": false}, {"id": "B", "text": "3G", "isCorrect": false}, {"id": "C", "text": "4G", "isCorrect": false}, {"id": "D", "text": "5G", "isCorrect": true}]', 'D', 5, '2026-03-18 08:28:34.188', '2026-03-18 08:28:34.188', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jko002jugv7i9ewxy2v', 'SOAL-00046', 'Seiring dengan pertumbuhan perangkat yang terhubung ke internet, jumlah alamat IP yang tersedia menjadi krusial. Sistem pengalamatan yang dikembangkan untuk mengatasi keterbatasan jumlah alamat IP pada versi sebelumnya dan memiliki ruang alamat yang jauh lebih besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "IPv4", "isCorrect": false}, {"id": "B", "text": "MAC Address", "isCorrect": false}, {"id": "C", "text": "IPv6", "isCorrect": true}, {"id": "D", "text": "DNS", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.2', '2026-03-18 08:28:34.2', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jl0002kugv7obukjh6j', 'SOAL-00047', 'Salah satu keunggulan utama IPv6 dibandingkan IPv4 adalah jumlah alamat yang jauh lebih banyak. Berapa bit yang digunakan oleh IPv6 untuk representasi alamat?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "32 bit", "isCorrect": false}, {"id": "B", "text": "64 bit", "isCorrect": false}, {"id": "C", "text": "128 bit", "isCorrect": true}, {"id": "D", "text": "256 bit", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.212', '2026-03-18 08:28:34.212', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jlg002lugv7simotm2z', 'SOAL-00048', 'Layanan yang memungkinkan pengguna menyimpan data dan menjalankan aplikasi di server yang dikelola oleh pihak ketiga melalui internet, sehingga mengurangi kebutuhan akan perangkat keras server fisik di lokasi pengguna, dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peer-to-Peer Computing", "isCorrect": false}, {"id": "B", "text": "Edge Computing", "isCorrect": false}, {"id": "C", "text": "Cloud Computing", "isCorrect": true}, {"id": "D", "text": "Local Area Network", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.227', '2026-03-18 08:28:34.227', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jlu002mugv71u41vcjw', 'SOAL-00049', 'Sebuah perusahaan startup sedang berkembang pesat dan membutuhkan infrastruktur IT yang fleksibel, scalable, dan hemat biaya tanpa harus membeli dan memelihara banyak server fisik. Solusi teknologi modern yang paling tepat untuk kebutuhan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membangun data center sendiri", "isCorrect": false}, {"id": "B", "text": "Menggunakan Cloud Computing", "isCorrect": true}, {"id": "C", "text": "Memperbanyak hard disk lokal", "isCorrect": false}, {"id": "D", "text": "Meningkatkan kecepatan koneksi internet saja", "isCorrect": false}]', 'B', 5, '2026-03-18 08:28:34.241', '2026-03-18 08:28:34.241', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jmb002nugv7914kbdi8', 'SOAL-00050', 'Konsep di mana berbagai perangkat mekanis atau digital dapat saling berkomunikasi dan mentransfer data melalui jaringan tanpa interaksi manusia secara langsung disebut...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Human-to-Human Communication", "isCorrect": false}, {"id": "B", "text": "Machine-to-Machine (M2M) Communication", "isCorrect": true}, {"id": "C", "text": "Peer-to-Peer File Sharing", "isCorrect": false}, {"id": "D", "text": "Client-Server Architecture", "isCorrect": false}]', 'B', 5, '2026-03-18 08:28:34.258', '2026-03-18 08:28:34.258', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jmn002ougv7qyr6cbm4', 'SOAL-00051', 'Sebuah smart home memiliki lampu pintar, termostat otomatis, dan kamera keamanan yang semuanya terhubung ke internet dan dapat dikendalikan dari smartphone pengguna. Ini adalah contoh implementasi dari...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Cloud Computing", "isCorrect": false}, {"id": "B", "text": "Data Center Redundan", "isCorrect": false}, {"id": "C", "text": "Internet of Things (IoT)", "isCorrect": true}, {"id": "D", "text": "Jaringan Dedicated", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.27', '2026-03-18 08:28:34.27', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jmy002pugv77bqbcndr', 'SOAL-00052', 'Untuk memastikan ketersediaan data yang tinggi dan mencegah kegagalan sistem total, sebuah perusahaan membangun infrastruktur penyimpanan data yang memiliki sistem cadangan atau paralel. Konsep ini dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Data Center Terdistribusi", "isCorrect": false}, {"id": "B", "text": "Data Center Virtual", "isCorrect": false}, {"id": "C", "text": "Data Center Redundan", "isCorrect": true}, {"id": "D", "text": "Data Center Lokal", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.281', '2026-03-18 08:28:34.281', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jn9002qugv7ss4sv279', 'SOAL-00053', 'Sebuah layanan streaming video global harus memastikan layanannya selalu tersedia 24/7 tanpa gangguan, bahkan jika terjadi bencana alam di salah satu lokasi server. Solusi infrastruktur yang paling krusial untuk mencapai tujuan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Menggunakan server dengan spesifikasi tertinggi", "isCorrect": false}, {"id": "B", "text": "Membangun Data Center Redundan di lokasi geografis yang berbeda", "isCorrect": true}, {"id": "C", "text": "Hanya mengandalkan satu data center yang sangat besar", "isCorrect": false}, {"id": "D", "text": "Meningkatkan bandwidth koneksi internet ke pengguna", "isCorrect": false}]', 'B', 5, '2026-03-18 08:28:34.292', '2026-03-18 08:28:34.292', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jnj002rugv7jgmu4ff4', 'SOAL-00054', 'Perusahaan X masih menggunakan jaringan terpisah untuk telepon, TV kabel, dan koneksi internet di kantor pusatnya. Mereka ingin beralih ke Jaringan Converged. Keuntungan utama yang akan mereka dapatkan dari transisi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peningkatan kompleksitas pengelolaan jaringan.", "isCorrect": false}, {"id": "B", "text": "Peningkatan biaya investasi awal yang signifikan.", "isCorrect": false}, {"id": "C", "text": "Efisiensi biaya dan manajemen yang lebih sederhana karena satu infrastruktur.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat mendukung satu jenis layanan pada satu waktu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.303', '2026-03-18 08:28:34.303', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jnu002sugv72sirugpm', 'SOAL-00055', 'Mengapa serat optik lebih unggul dibandingkan kabel tembaga (misalnya UTP) untuk transmisi data jarak jauh dan kecepatan tinggi dalam Jaringan Converged?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Lebih murah dan mudah dipasang.", "isCorrect": false}, {"id": "B", "text": "Mentransmisikan data dalam bentuk sinyal listrik.", "isCorrect": false}, {"id": "C", "text": "Kurang rentan terhadap interferensi elektromagnetik dan memiliki bandwidth lebih besar.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat digunakan untuk jaringan lokal.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.313', '2026-03-18 08:28:34.313', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jo5002tugv7vksoovhz', 'SOAL-00056', 'Dalam konteks IPv6, penggunaan format heksadesimal (misalnya, 2001:0db8:85a3:0000:0000:8a2e:0370:7334) untuk alamat IP dibandingkan notasi desimal bertitik pada IPv4 (misalnya, 192.168.1.1) memiliki tujuan utama untuk...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mempermudah mengingat alamat IP oleh pengguna awam.", "isCorrect": false}, {"id": "B", "text": "Mengurangi ukuran file konfigurasi jaringan.", "isCorrect": false}, {"id": "C", "text": "Meringkas representasi alamat yang panjang agar lebih efisien.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan keamanan jaringan secara inheren.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.324', '2026-03-18 08:28:34.324', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4joh002uugv7c8bt7i6m', 'SOAL-00057', 'Sebuah kota berencana menerapkan ''Smart City'' dengan sensor parkir pintar, sistem pengelolaan sampah otomatis, dan pemantauan kualitas udara secara real-time. Infrastruktur jaringan nirkabel seperti 5G akan sangat penting untuk mendukung proyek ini karena...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Harganya yang murah untuk pemasangan awal.", "isCorrect": false}, {"id": "B", "text": "Latensi tinggi yang cocok untuk transmisi data masif.", "isCorrect": false}, {"id": "C", "text": "Kecepatan tinggi, latensi rendah, dan kapasitas koneksi perangkat masif.", "isCorrect": true}, {"id": "D", "text": "Kebutuhan daya yang rendah untuk perangkat sensor.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.337', '2026-03-18 08:28:34.337', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jou002vugv7jib2m371', 'SOAL-00058', 'Seorang teknisi jaringan sedang merancang ulang infrastruktur untuk sebuah e-commerce besar yang tidak boleh mengalami downtime sedikit pun. Dia menyarankan penggunaan teknologi Data Center Redundan. Apa prinsip dasar yang ingin dicapai dengan rekomendasi ini?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mengurangi konsumsi energi secara drastis.", "isCorrect": false}, {"id": "B", "text": "Memastikan semua data disimpan secara lokal di setiap perangkat.", "isCorrect": false}, {"id": "C", "text": "Mencegah satu titik kegagalan (Single Point of Failure) agar layanan tetap berjalan.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan kecepatan akses data untuk pengguna individu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:28:34.349', '2026-03-18 08:28:34.349', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jp4002wugv79y4ackeq', 'SOAL-00059', 'Dalam Cloud Computing, salah satu manfaat bagi pengguna adalah ''pay-as-you-go'' atau membayar sesuai penggunaan. Implikasi utama dari model ini bagi sebuah bisnis kecil yang baru memulai adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membutuhkan investasi awal yang sangat besar untuk hardware.", "isCorrect": false}, {"id": "B", "text": "Memungkinkan skalabilitas sumber daya tanpa komitmen jangka panjang.", "isCorrect": true}, {"id": "C", "text": "Mengharuskan pemeliharaan server secara mandiri.", "isCorrect": false}, {"id": "D", "text": "Membatasi akses ke aplikasi dan data hanya di lokasi fisik kantor.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:28:34.36', '2026-03-18 08:28:34.36', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tcu0018ugv7gasaeall', 'SOAL-00021', 'Sebelum era internet modern, layanan komunikasi seperti telepon, televisi, dan data seringkali menggunakan infrastruktur jaringan yang terpisah. Istilah yang tepat untuk menggambarkan jenis jaringan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Jaringan Konvergen", "isCorrect": false}, {"id": "B", "text": "Jaringan Terintegrasi", "isCorrect": false}, {"id": "C", "text": "Jaringan Dedicated", "isCorrect": true}, {"id": "D", "text": "Jaringan Nirkabel", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.91', '2026-03-18 08:26:26.91', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs4jpf002xugv76gzxkebe', 'SOAL-00060', 'Perusahaan telekomunikasi sedang dalam proses migrasi dari infrastruktur Jaringan Dedicated ke Jaringan Converged menggunakan TCP/IP. Tantangan teknis utama yang mungkin mereka hadapi dalam proses migrasi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kurangnya perangkat keras yang mendukung TCP/IP.", "isCorrect": false}, {"id": "B", "text": "Kompatibilitas antara sistem lama (analog) dengan protokol baru (digital) dan investasi besar.", "isCorrect": true}, {"id": "C", "text": "Keterbatasan jumlah alamat IP yang tersedia di Jaringan Converged.", "isCorrect": false}, {"id": "D", "text": "Peningkatan kecepatan internet yang tidak terkendali.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:28:34.37', '2026-03-18 08:28:34.37', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1td80019ugv7gkjty9mq', 'SOAL-00022', 'Perkembangan teknologi jaringan telah mengubah paradigma dari jaringan yang terpisah-pisah menjadi satu kesatuan. Manakah pernyataan berikut yang paling tepat menggambarkan karakteristik utama ''Jaringan Converged''?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Hanya mendukung komunikasi suara dan video secara bersamaan.", "isCorrect": false}, {"id": "B", "text": "Menggunakan infrastruktur terpisah untuk setiap jenis layanan (suara, data, video).", "isCorrect": false}, {"id": "C", "text": "Mengintegrasikan berbagai jenis komunikasi (suara, data, video) dalam satu infrastruktur jaringan.", "isCorrect": true}, {"id": "D", "text": "Membutuhkan protokol yang berbeda untuk setiap jenis data yang ditransmisikan.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.923', '2026-03-18 08:26:26.923', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tdh001augv7qw38dgz0', 'SOAL-00023', 'Protokol standar yang menjadi fondasi utama dalam Jaringan Converged dan memungkinkan berbagai perangkat serta layanan untuk saling berkomunikasi di era internet adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "FTP/HTTP", "isCorrect": false}, {"id": "B", "text": "SMTP/POP3", "isCorrect": false}, {"id": "C", "text": "TCP/IP", "isCorrect": true}, {"id": "D", "text": "UDP/ICMP", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.932', '2026-03-18 08:26:26.932', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tdu001bugv7nm8zw8zy', 'SOAL-00024', 'Media komunikasi yang menggunakan cahaya untuk mentransmisikan data dengan kecepatan sangat tinggi dan menjadi tulang punggung infrastruktur jaringan modern adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kabel koaksial", "isCorrect": false}, {"id": "B", "text": "Kabel UTP", "isCorrect": false}, {"id": "C", "text": "Serat optik", "isCorrect": true}, {"id": "D", "text": "Gelombang radio", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.945', '2026-03-18 08:26:26.945', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1te7001cugv7ylcp63kk', 'SOAL-00025', 'Peningkatan kecepatan transfer data secara signifikan merupakan salah satu ciri kemajuan teknologi nirkabel. Generasi teknologi nirkabel yang mampu mencapai kecepatan gigabit per detik dan mendukung berbagai aplikasi canggih seperti IoT skala besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "2G", "isCorrect": false}, {"id": "B", "text": "3G", "isCorrect": false}, {"id": "C", "text": "4G", "isCorrect": false}, {"id": "D", "text": "5G", "isCorrect": true}]', 'D', 5, '2026-03-18 08:26:26.958', '2026-03-18 08:26:26.958', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tei001dugv71863sute', 'SOAL-00026', 'Seiring dengan pertumbuhan perangkat yang terhubung ke internet, jumlah alamat IP yang tersedia menjadi krusial. Sistem pengalamatan yang dikembangkan untuk mengatasi keterbatasan jumlah alamat IP pada versi sebelumnya dan memiliki ruang alamat yang jauh lebih besar adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "IPv4", "isCorrect": false}, {"id": "B", "text": "MAC Address", "isCorrect": false}, {"id": "C", "text": "IPv6", "isCorrect": true}, {"id": "D", "text": "DNS", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.97', '2026-03-18 08:26:26.97', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tev001eugv7dgd4rzd2', 'SOAL-00027', 'Salah satu keunggulan utama IPv6 dibandingkan IPv4 adalah jumlah alamat yang jauh lebih banyak. Berapa bit yang digunakan oleh IPv6 untuk representasi alamat?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "32 bit", "isCorrect": false}, {"id": "B", "text": "64 bit", "isCorrect": false}, {"id": "C", "text": "128 bit", "isCorrect": true}, {"id": "D", "text": "256 bit", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.981', '2026-03-18 08:26:26.981', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tf8001fugv7bg8butsf', 'SOAL-00028', 'Layanan yang memungkinkan pengguna menyimpan data dan menjalankan aplikasi di server yang dikelola oleh pihak ketiga melalui internet, sehingga mengurangi kebutuhan akan perangkat keras server fisik di lokasi pengguna, dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peer-to-Peer Computing", "isCorrect": false}, {"id": "B", "text": "Edge Computing", "isCorrect": false}, {"id": "C", "text": "Cloud Computing", "isCorrect": true}, {"id": "D", "text": "Local Area Network", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:26.995', '2026-03-18 08:26:26.995', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tfk001gugv70meono23', 'SOAL-00029', 'Sebuah perusahaan startup sedang berkembang pesat dan membutuhkan infrastruktur IT yang fleksibel, scalable, dan hemat biaya tanpa harus membeli dan memelihara banyak server fisik. Solusi teknologi modern yang paling tepat untuk kebutuhan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membangun data center sendiri", "isCorrect": false}, {"id": "B", "text": "Menggunakan Cloud Computing", "isCorrect": true}, {"id": "C", "text": "Memperbanyak hard disk lokal", "isCorrect": false}, {"id": "D", "text": "Meningkatkan kecepatan koneksi internet saja", "isCorrect": false}]', 'B', 5, '2026-03-18 08:26:27.007', '2026-03-18 08:26:27.007', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tfw001hugv72aq2h9ck', 'SOAL-00030', 'Konsep di mana berbagai perangkat mekanis atau digital dapat saling berkomunikasi dan mentransfer data melalui jaringan tanpa interaksi manusia secara langsung disebut...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Human-to-Human Communication", "isCorrect": false}, {"id": "B", "text": "Machine-to-Machine (M2M) Communication", "isCorrect": true}, {"id": "C", "text": "Peer-to-Peer File Sharing", "isCorrect": false}, {"id": "D", "text": "Client-Server Architecture", "isCorrect": false}]', 'B', 5, '2026-03-18 08:26:27.019', '2026-03-18 08:26:27.019', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tg7001iugv7h4blcxrv', 'SOAL-00031', 'Sebuah smart home memiliki lampu pintar, termostat otomatis, dan kamera keamanan yang semuanya terhubung ke internet dan dapat dikendalikan dari smartphone pengguna. Ini adalah contoh implementasi dari...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Cloud Computing", "isCorrect": false}, {"id": "B", "text": "Data Center Redundan", "isCorrect": false}, {"id": "C", "text": "Internet of Things (IoT)", "isCorrect": true}, {"id": "D", "text": "Jaringan Dedicated", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.03', '2026-03-18 08:26:27.03', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tgi001jugv7h7c5p24f', 'SOAL-00032', 'Untuk memastikan ketersediaan data yang tinggi dan mencegah kegagalan sistem total, sebuah perusahaan membangun infrastruktur penyimpanan data yang memiliki sistem cadangan atau paralel. Konsep ini dikenal sebagai...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Data Center Terdistribusi", "isCorrect": false}, {"id": "B", "text": "Data Center Virtual", "isCorrect": false}, {"id": "C", "text": "Data Center Redundan", "isCorrect": true}, {"id": "D", "text": "Data Center Lokal", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.041', '2026-03-18 08:26:27.041', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tgu001kugv747g56ll3', 'SOAL-00033', 'Sebuah layanan streaming video global harus memastikan layanannya selalu tersedia 24/7 tanpa gangguan, bahkan jika terjadi bencana alam di salah satu lokasi server. Solusi infrastruktur yang paling krusial untuk mencapai tujuan ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Menggunakan server dengan spesifikasi tertinggi", "isCorrect": false}, {"id": "B", "text": "Membangun Data Center Redundan di lokasi geografis yang berbeda", "isCorrect": true}, {"id": "C", "text": "Hanya mengandalkan satu data center yang sangat besar", "isCorrect": false}, {"id": "D", "text": "Meningkatkan bandwidth koneksi internet ke pengguna", "isCorrect": false}]', 'B', 5, '2026-03-18 08:26:27.053', '2026-03-18 08:26:27.053', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1th7001lugv7f32z9jax', 'SOAL-00034', 'Perusahaan X masih menggunakan jaringan terpisah untuk telepon, TV kabel, dan koneksi internet di kantor pusatnya. Mereka ingin beralih ke Jaringan Converged. Keuntungan utama yang akan mereka dapatkan dari transisi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Peningkatan kompleksitas pengelolaan jaringan.", "isCorrect": false}, {"id": "B", "text": "Peningkatan biaya investasi awal yang signifikan.", "isCorrect": false}, {"id": "C", "text": "Efisiensi biaya dan manajemen yang lebih sederhana karena satu infrastruktur.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat mendukung satu jenis layanan pada satu waktu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.066', '2026-03-18 08:26:27.066', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1thj001mugv7bd4kuo97', 'SOAL-00035', 'Mengapa serat optik lebih unggul dibandingkan kabel tembaga (misalnya UTP) untuk transmisi data jarak jauh dan kecepatan tinggi dalam Jaringan Converged?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Lebih murah dan mudah dipasang.", "isCorrect": false}, {"id": "B", "text": "Mentransmisikan data dalam bentuk sinyal listrik.", "isCorrect": false}, {"id": "C", "text": "Kurang rentan terhadap interferensi elektromagnetik dan memiliki bandwidth lebih besar.", "isCorrect": true}, {"id": "D", "text": "Hanya dapat digunakan untuk jaringan lokal.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.078', '2026-03-18 08:26:27.078', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1thv001nugv7x0juquva', 'SOAL-00036', 'Dalam konteks IPv6, penggunaan format heksadesimal (misalnya, 2001:0db8:85a3:0000:0000:8a2e:0370:7334) untuk alamat IP dibandingkan notasi desimal bertitik pada IPv4 (misalnya, 192.168.1.1) memiliki tujuan utama untuk...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mempermudah mengingat alamat IP oleh pengguna awam.", "isCorrect": false}, {"id": "B", "text": "Mengurangi ukuran file konfigurasi jaringan.", "isCorrect": false}, {"id": "C", "text": "Meringkas representasi alamat yang panjang agar lebih efisien.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan keamanan jaringan secara inheren.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.091', '2026-03-18 08:26:27.091', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1ti6001ougv7q0oblxqy', 'SOAL-00037', 'Sebuah kota berencana menerapkan ''Smart City'' dengan sensor parkir pintar, sistem pengelolaan sampah otomatis, dan pemantauan kualitas udara secara real-time. Infrastruktur jaringan nirkabel seperti 5G akan sangat penting untuk mendukung proyek ini karena...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Harganya yang murah untuk pemasangan awal.", "isCorrect": false}, {"id": "B", "text": "Latensi tinggi yang cocok untuk transmisi data masif.", "isCorrect": false}, {"id": "C", "text": "Kecepatan tinggi, latensi rendah, dan kapasitas koneksi perangkat masif.", "isCorrect": true}, {"id": "D", "text": "Kebutuhan daya yang rendah untuk perangkat sensor.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.102', '2026-03-18 08:26:27.102', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tii001pugv77crpjdnt', 'SOAL-00038', 'Seorang teknisi jaringan sedang merancang ulang infrastruktur untuk sebuah e-commerce besar yang tidak boleh mengalami downtime sedikit pun. Dia menyarankan penggunaan teknologi Data Center Redundan. Apa prinsip dasar yang ingin dicapai dengan rekomendasi ini?', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Mengurangi konsumsi energi secara drastis.", "isCorrect": false}, {"id": "B", "text": "Memastikan semua data disimpan secara lokal di setiap perangkat.", "isCorrect": false}, {"id": "C", "text": "Mencegah satu titik kegagalan (Single Point of Failure) agar layanan tetap berjalan.", "isCorrect": true}, {"id": "D", "text": "Meningkatkan kecepatan akses data untuk pengguna individu.", "isCorrect": false}]', 'C', 5, '2026-03-18 08:26:27.113', '2026-03-18 08:26:27.113', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tiu001qugv7kw2x532a', 'SOAL-00039', 'Dalam Cloud Computing, salah satu manfaat bagi pengguna adalah ''pay-as-you-go'' atau membayar sesuai penggunaan. Implikasi utama dari model ini bagi sebuah bisnis kecil yang baru memulai adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Membutuhkan investasi awal yang sangat besar untuk hardware.", "isCorrect": false}, {"id": "B", "text": "Memungkinkan skalabilitas sumber daya tanpa komitmen jangka panjang.", "isCorrect": true}, {"id": "C", "text": "Mengharuskan pemeliharaan server secara mandiri.", "isCorrect": false}, {"id": "D", "text": "Membatasi akses ke aplikasi dan data hanya di lokasi fisik kantor.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:26:27.126', '2026-03-18 08:26:27.126', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
INSERT INTO public."BankSoal" (id, kode, pertanyaan, tipe, "mataPelajaranId", "pilihanJawaban", "jawabanBenar", bobot, "createdAt", "updatedAt", "deletedAt", "guruId", "kelasId", "kelompokSoalId") VALUES ('cmmvs1tj7001rugv7x0igz6u1', 'SOAL-00040', 'Perusahaan telekomunikasi sedang dalam proses migrasi dari infrastruktur Jaringan Dedicated ke Jaringan Converged menggunakan TCP/IP. Tantangan teknis utama yang mungkin mereka hadapi dalam proses migrasi ini adalah...', 'PILIHAN_GANDA', 'cmj9z7q9c001p5dudhh2cp17a', '[{"id": "A", "text": "Kurangnya perangkat keras yang mendukung TCP/IP.", "isCorrect": false}, {"id": "B", "text": "Kompatibilitas antara sistem lama (analog) dengan protokol baru (digital) dan investasi besar.", "isCorrect": true}, {"id": "C", "text": "Keterbatasan jumlah alamat IP yang tersedia di Jaringan Converged.", "isCorrect": false}, {"id": "D", "text": "Peningkatan kecepatan internet yang tidak terkendali.", "isCorrect": false}]', 'B', 5, '2026-03-18 08:26:27.138', '2026-03-18 08:26:27.138', NULL, 'cmj9z8y1b002c5dudh3e7fyuu', 'cmj5ec9zf0000jsudgpxci2hf', NULL);
