INSERT INTO public."RPP" (id, kode, "mataPelajaranId", "guruId", "capaianPembelajaran", "tujuanPembelajaran", status, "isPublished", "createdAt", "updatedAt", "deletedAt", "alokasiWaktu", "asesmenAkhir", "asesmenAwal", "asesmenProses", "dimensiProfilLulusan", fase, "identifikasiMateri", "identifikasiPesertaDidik", "kegiatanAwal", "kegiatanMemahami", "kegiatanMengaplikasi", "kegiatanMerefleksi", "kegiatanPenutup", "kemitraanPembelajaran", "lingkunganPembelajaran", "lintasDisiplinIlmu", materi, "namaGuru", "pemanfaatanDigital", "praktikPedagogik", "tahunAjaran", "topikPembelajaran") VALUES ('cmjsihj2y0000v5ud7f0f6syr', 'RPP-DPK', 'cmj9z7q9n001s5dudxr525koc', 'cmj9z8yem002u5dudolwskcz4', 'Pada akhir fase F, peserta didik mampu mengelola dan mengamankan jaringan komputer berbasis kabel dan nirkabel, termasuk mengkonfigurasi perangkat jaringan aktif, menerapkan protokol jaringan, serta melakukan pemeliharaan dan perbaikan. Secara spesifik, peserta didik mampu mengkonfigurasi perangkat jaringan Mikrotik untuk membangun konektivitas dasar dan layanan jaringan esensial sesuai standar operasional prosedur dan kebutuhan fungsional.', '["Setelah mengikuti sesi diskusi dan demonstrasi, peserta didik mampu menjelaskan fungsi dan konsep dasar komponen Mikrotik (misalnya, Winbox, IP Address, DHCP Server, DNS, Gateway) dengan tepat dan percaya diri.", "Melalui kegiatan praktikum mandiri, peserta didik mampu mengaplikasikan langkah-langkah setting dasar Mikrotik (identitas router, konfigurasi IP Address, DHCP Server, DNS, dan Gateway) pada perangkat fisik atau virtual dengan akurat dan sesuai prosedur.", "Melalui studi kasus sederhana, peserta didik mampu menganalisis dan mengidentifikasi potensi permasalahan pada konfigurasi dasar Mikrotik serta mengusulkan solusi secara logis dan kritis."]', 'PUBLISHED', true, '2025-12-30 11:36:18.393', '2025-12-30 11:45:05.838', '2025-12-30 11:45:05.835', 90, '1. **Unjuk Kerja/Praktik:** Peserta didik diminta untuk mendemonstrasikan konfigurasi dasar Mikrotik sesuai skenario yang diberikan (misalnya, ''Konfigurasikan Mikrotik ini agar dapat memberikan internet ke 3 komputer klien dan 1 perangkat Wi-Fi''). Penilaian berdasarkan rubrik yang mencakup ketepatan konfigurasi, fungsionalitas, efisiensi, dan kemampuan troubleshooting.
INSERT INTO public."RPP" (id, kode, "mataPelajaranId", "guruId", "capaianPembelajaran", "tujuanPembelajaran", status, "isPublished", "createdAt", "updatedAt", "deletedAt", "alokasiWaktu", "asesmenAkhir", "asesmenAwal", "asesmenProses", "dimensiProfilLulusan", fase, "identifikasiMateri", "identifikasiPesertaDidik", "kegiatanAwal", "kegiatanMemahami", "kegiatanMengaplikasi", "kegiatanMerefleksi", "kegiatanPenutup", "kemitraanPembelajaran", "lingkunganPembelajaran", "lintasDisiplinIlmu", materi, "namaGuru", "pemanfaatanDigital", "praktikPedagogik", "tahunAjaran", "topikPembelajaran") VALUES ('cmjsiy5ed000096ud77slyg7m', 'RPP-DPK-001', 'cmj9z7q87001e5dudb1uk5u9j', 'cmj9z8yem002u5dudolwskcz4', 'Pada akhir fase F, peserta didik mampu menerapkan dasar-dasar sistem jaringan komputer, mengidentifikasi komponen jaringan, serta mengimplementasikan konfigurasi dasar jaringan kabel dan nirkabel secara mandiri atau berkelompok untuk mendukung konektivitas data dan informasi.', '["Peserta didik mampu menjelaskan konsep dasar jaringan kabel dan nirkabel (jenis, komponen, topologi) dengan tepat setelah mengikuti diskusi dan presentasi. (PENALARAN_KRITIS)", "Peserta didik mampu mengidentifikasi dan membedakan komponen perangkat keras yang diperlukan untuk membangun jaringan kabel dan nirkabel melalui observasi dan eksplorasi. (PENALARAN_KRITIS)", "Peserta didik mampu mengimplementasikan konfigurasi dasar jaringan kabel menggunakan simulasi atau perangkat fisik sederhana secara kolaboratif dalam kelompok. (KREATIFITAS, KOLABORASI)"]', 'PUBLISHED', true, '2025-12-30 11:49:13.811', '2026-01-19 03:40:45.278', '2026-01-19 03:40:45.276', 90, 'Unjuk kerja/Portofolio: Hasil konfigurasi jaringan kabel dan nirkabel pada perangkat simulasi atau fisik yang diunggah atau didokumentasikan, disertai penjelasan singkat tentang langkah-langkah dan hasil pengujian. Penilaian refleksi individu (kedalaman pemahaman, kesadaran diri terhadap proses belajar).', 'Observasi partisipasi dan jawaban lisan peserta didik saat apersepsi dan asesmen diagnostik singkat tentang pengetahuan dasar jaringan (misalnya, ''Apa itu IP address?'', ''Apa fungsi router?'').', 'Observasi guru selama diskusi kelompok (keaktifan, kolaborasi, kemampuan berargumen, PENALARAN_KRITIS). Observasi performa saat praktikum (ketepatan mengikuti prosedur, kemampuan memecahkan masalah, KREATIFITAS dalam mencari solusi, KOLABORASI). Penilaian lembar kerja praktikum (kelengkapan konfigurasi, hasil pengujian konektivitas).', '["PENALARAN_KRITIS", "KREATIFITAS", "KOLABORASI"]', 'Fase F/X/Ganjil', 'Materi ''Konfigurasi Jaringan Kabel dan Nirkabel'' mencakup pengetahuan konseptual (jenis-jenis jaringan, protokol, topologi) dan prosedural (langkah-langkah konfigurasi perangkat). Materi ini sangat relevan dengan kehidupan sehari-hari peserta didik (penggunaan internet, Wi-Fi) dan menjadi dasar penting dalam program keahlian TKJ. Tingkat kesulitan materi ini moderat, membutuhkan pemahaman teori dasar sebelum dapat diaplikasikan secara praktis. Materi ini mendorong peserta didik untuk berpikir kritis dalam memecahkan masalah konfigurasi.', 'Peserta didik Fase F di SMK kelas X umumnya berada pada tahap perkembangan kognitif operasional formal, mampu berpikir abstrak namun masih memerlukan konteks konkret. Mereka memiliki tingkat literasi digital yang bervariasi, beberapa mungkin sudah memiliki pengetahuan dasar tentang jaringan dari pengalaman pribadi atau media sosial. Kesiapan belajar mereka dapat beragam, ada yang antusias dengan praktik, ada pula yang lebih suka teori. Minat mereka cenderung pada hal-hal aplikatif dan relevan dengan dunia kerja. Beberapa mungkin memiliki gaya belajar visual, auditori, atau kinestetik. Peserta didik diharapkan dapat bekerja secara kolaboratif dalam kelompok.', '{"prinsip": ["Mindful", "Meaningful"], "kegiatan": "1. Guru membuka pelajaran dengan salam dan memimpin doa. (Mindful)\n2. Guru mengecek kehadiran dan kesiapan belajar peserta didik.\n3. Guru melakukan apersepsi dengan menampilkan video singkat atau gambar tentang penggunaan jaringan internet dalam kehidupan sehari-hari (misalnya, di rumah, sekolah, tempat kerja) dan menanyakan ''Apa yang kalian ketahui tentang bagaimana perangkat-perangkat ini bisa saling terhubung?'' (Meaningful, Mindful)\n4. Guru menjelaskan tujuan pembelajaran dan manfaat mempelajari konfigurasi jaringan dalam dunia kerja TKJ.\n5. Guru melakukan asesmen diagnostik singkat (pertanyaan lisan atau polling sederhana) untuk mengetahui pengetahuan awal peserta didik tentang jaringan komputer. Contoh: ''Siapa yang tahu bedanya jaringan kabel dan nirkabel?''"}', '{"prinsip": ["Meaningful", "Mindful"], "kegiatan": "1. Peserta didik dibagi menjadi beberapa kelompok kecil (3-4 orang).\n2. Setiap kelompok diberikan studi kasus sederhana tentang kebutuhan jaringan di sebuah kantor kecil atau rumah. (Meaningful)\n3. Guru memfasilitasi diskusi kelompok untuk mengidentifikasi jenis-jenis jaringan (LAN, WLAN), komponen utama (router, switch, kabel, NIC, AP), dan topologi dasar yang mungkin digunakan dalam studi kasus tersebut. Peserta didik dapat mencari informasi dari buku paket atau sumber online. (Meaningful, Mindful, PENALARAN_KRITIS)\n4. Guru memberikan penjelasan singkat dan interaktif tentang konsep-konsep kunci (IP address, subnet mask, gateway, DHCP) yang akan digunakan dalam konfigurasi, menggunakan contoh-contoh yang relevan.\n5. Setiap kelompok diminta mempresentasikan hasil diskusi awal mereka tentang komponen dan topologi yang akan mereka pilih."}', '{"prinsip": ["Meaningful", "Joyful"], "kegiatan": "1. Guru mendemonstrasikan langkah-langkah dasar konfigurasi jaringan kabel pada perangkat lunak simulasi (misalnya, Cisco Packet Tracer) atau perangkat fisik sederhana (misalnya, menghubungkan PC ke switch, memberikan IP address statis). (Meaningful)\n2. Setiap kelompok menerima lembar kerja praktikum yang berisi skenario konfigurasi dasar jaringan kabel dan nirkabel.\n3. Peserta didik secara berkelompok memulai praktikum konfigurasi jaringan sesuai skenario, baik menggunakan Cisco Packet Tracer atau perangkat fisik yang tersedia. Mereka diminta untuk mengkonfigurasi IP Address, menguji konektivitas (ping), dan jika memungkinkan, mengkonfigurasi SSID dan password pada perangkat nirkabel. (Meaningful, Joyful, KREATIFITAS, KOLABORASI)\n4. Guru memfasilitasi dan membimbing peserta didik, memberikan bantuan jika diperlukan, dan mendorong diskusi antar anggota kelompok untuk memecahkan masalah."}', '{"prinsip": ["Mindful"], "kegiatan": "1. Setiap kelompok diminta untuk menuliskan secara singkat kendala yang mereka hadapi selama praktikum dan bagaimana mereka mengatasinya.\n2. Guru memimpin diskusi singkat tentang ''Apa hal baru yang kalian pelajari hari ini?'' dan ''Bagian mana dari konfigurasi yang paling menantang dan mengapa?''. (Mindful)\n3. Peserta didik secara individu menuliskan satu hal penting yang mereka pahami dari pembelajaran hari ini dan satu pertanyaan yang masih ingin mereka ketahui."}', '{"prinsip": ["Mindful"], "kegiatan": "1. Guru bersama peserta didik menyimpulkan poin-poin penting pembelajaran hari ini.\n2. Guru memberikan apresiasi atas partisipasi aktif peserta didik.\n3. Guru menyampaikan materi untuk pertemuan selanjutnya (misalnya, troubleshooting jaringan sederhana).\n4. Guru menutup pelajaran dengan doa dan salam."}', 'Belum ada kemitraan khusus untuk sesi ini.', 'Laboratorium komputer dengan akses internet dan perangkat lunak simulasi jaringan (misalnya Cisco Packet Tracer) atau laboratorium praktik dengan perangkat jaringan fisik sederhana (switch, router Wi-Fi, kabel UTP, PC/laptop). Budaya belajar yang kolaboratif, saling membantu, dan mendorong eksperimen.', 'Informatika (algoritma, logika), Matematika (perhitungan IP address, subnetting), Bahasa Indonesia (komunikasi teknis, penulisan laporan).', 'Konfigurasi Jaringan Kabel dan Nirkabel', NULL, 'Perangkat lunak simulasi jaringan (Cisco Packet Tracer) untuk praktikum virtual. Sumber belajar daring (video tutorial, artikel teknis) untuk eksplorasi mandiri. Media presentasi digital (PowerPoint, Google Slides) untuk penjelasan konsep dan presentasi hasil.', 'Pembelajaran Berbasis Proyek (Project-Based Learning) atau Pembelajaran Berbasis Masalah (Problem-Based Learning) dengan pendekatan Deep Learning, di mana peserta didik tidak hanya menghafal prosedur tetapi memahami ''mengapa'' dan ''bagaimana'' suatu konfigurasi bekerja, serta mampu memecahkan masalah. Metode diskusi, demonstrasi, dan praktikum mandiri/kelompok.', '2025-2026', 'Konfigurasi Dasar Jaringan Kabel (LAN) dan Jaringan Nirkabel (WLAN) menggunakan perangkat simulasi atau perangkat fisik sederhana (router, switch, kabel UTP).');
INSERT INTO public."RPP" (id, kode, "mataPelajaranId", "guruId", "capaianPembelajaran", "tujuanPembelajaran", status, "isPublished", "createdAt", "updatedAt", "deletedAt", "alokasiWaktu", "asesmenAkhir", "asesmenAwal", "asesmenProses", "dimensiProfilLulusan", fase, "identifikasiMateri", "identifikasiPesertaDidik", "kegiatanAwal", "kegiatanMemahami", "kegiatanMengaplikasi", "kegiatanMerefleksi", "kegiatanPenutup", "kemitraanPembelajaran", "lingkunganPembelajaran", "lintasDisiplinIlmu", materi, "namaGuru", "pemanfaatanDigital", "praktikPedagogik", "tahunAjaran", "topikPembelajaran") VALUES ('cmkkmg04f00018xpvkzn52tcn', 'RPP-01', 'cmj9z7q87001e5dudb1uk5u9j', 'cmj9z8yem002u5dudolwskcz4', 'Pada akhir Fase E, peserta didik mampu mengidentifikasi berbagai profesi dan peluang kewirausahaan di bidang Teknik Jaringan Komputer dan Telekomunikasi, serta merancang ide bisnis sederhana berdasarkan analisis kebutuhan pasar dan perkembangan teknologi.', '["Peserta didik mampu mengidentifikasi minimal 5 jenis profesi di bidang Teknik Jaringan Komputer dan Telekomunikasi dengan tepat setelah melakukan riset kelompok.", "Peserta didik mampu menganalisis peluang dan tantangan kewirausahaan di bidang Teknik Jaringan Komputer dan Telekomunikasi melalui studi kasus sederhana secara kolaboratif.", "Peserta didik terampil menyusun ide bisnis sederhana yang relevan dengan kebutuhan pasar di bidang Teknik Jaringan Komputer dan Telekomunikasi, ditunjukkan dengan hasil presentasi yang kreatif.", "Peserta didik menunjukkan sikap proaktif, mandiri, dan bertanggung jawab dalam mencari informasi serta berkolaborasi dalam kelompok terkait profesi dan kewirausahaan."]', 'PUBLISHED', true, '2026-01-19 03:44:38.558', '2026-01-19 03:44:38.558', NULL, 90, '1. Produk Proyek (Poster Digital/Infografis/Presentasi): Penilaian berdasarkan rubrik yang mencakup aspek: kelengkapan informasi, kedalaman analisis (PENALARAN KRITIS), kreativitas visual (KREATIFITAS), dan kejelasan penyampaian ide (KOMUNIKASI).
